      { scenario: "RAG search, 10M documents, 50K queries/day", hosted_cost: "~$3K/mo (OpenAI embeddings + Pinecone)", self_hosted_cost: "~$800/mo (e5-large on T4 + Qdrant on r6g.xlarge)", recommendation: "Depends on team — self-host if you have ML ops capability" }
